You can use the `HttpClient` class in ASP.NET Core to create a proxy to another endpoint. Here's a simple example of how you can do this:

**Proxy Controller**

```csharp
[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [HttpGet]
    public async Task<IActionResult> GetAsync([FromUri] string url)
    {
        var client = _httpClientFactory.CreateClient();
        var response = await client.GetAsync(url);

        return new ObjectResult(await response.Content.ReadAsStringAsync())
        {
            StatusCode = (int)response.StatusCode
        };
    }

    [HttpPost]
    public async Task<IActionResult> PostAsync([FromBody] string body, [FromUri] string url)
    {
        var client = _httpClientFactory.CreateClient();
        var content = new StringContent(body, Encoding.UTF8, "text/plain");
        var response = await client.PostAsync(url, content);

        return new ObjectResult(await response.Content.ReadAsStringAsync())
        {
            StatusCode = (int)response.StatusCode
        };
    }
}
```

